// -----------------------------------------------------------------------------
// UpdateInvoiceTotals
// Writes the service-computed money roll-up (net / sales tax / gross) after the
// lines have been (re)built. due_value_minor recomputes automatically (it's
// GENERATED from total_value_minor - paid_value_minor). paid_value_minor is NOT
// touched here — it has its own query.
// -----------------------------------------------------------------------------
func (q *Queries) UpdateInvoiceTotals(ctx context.Context, arg UpdateInvoiceTotalsParams) (Invoice, error) {
	row := q.db.QueryRow(ctx, updateInvoiceTotals,
		arg.ID,
		arg.OrganisationID,
		arg.NetValueMinor,
		arg.SalesTaxValueMinor,
		arg.TotalValueMinor,
	)
	var i Invoice
	err := row.Scan(
		&i.ID,
		&i.OrganisationID,
		&i.CreatedByUserID,
		&i.ContactID,
		&i.DatedOn,
		&i.DueOn,
		&i.Reference,
		&i.Currency,
		&i.Status,
		&i.NetValueMinor,
		&i.SalesTaxValueMinor,
		&i.TotalValueMinor,
		&i.PaidValueMinor,
		&i.DueValueMinor,
		&i.DeletedAt,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}
